def calc_replace_turnover(indicator_obj: Any, topk: int) -> tuple[float, float, float]:
    if indicator_obj is None or topk <= 0:
        return np.nan, np.nan, np.nan

    day_ratios = []
    try:
        for _, order_indicator in indicator_obj.order_indicator_his.items():
            trade_dir = order_indicator.get_index_data("trade_dir").to_dict()
            sells = sum(1 for v in trade_dir.values() if int(v) == 1)
            buys = sum(1 for v in trade_dir.values() if int(v) == 0)
            replaced = min(sells, buys)
            day_ratios.append(2.0 * replaced / topk)
    except Exception:
        return np.nan, np.nan, np.nan

    if not day_ratios:
        return 0.0, 0.0, 0.0

    sr = pd.Series(day_ratios, dtype=float)
    return float(sr.mean()), float(sr.quantile(0.95)), float(sr.max())

